# Category: information_disclosure

import Foundation

class AnalyticsLogger {

    static let shared = AnalyticsLogger()

    private init() {}

    private let logQueue = DispatchQueue(label: "com.yourapp.analytics.logQueue", qos: .background)

    // MARK: - General Logging

    func log(_ message: String, category: String = "General") {
        let timestamp = ISO8601DateFormatter().string(from: Date())
        logQueue.async {
            print("[\(timestamp)] [\(category)] \(message)")
            NSLog("[\(timestamp)] [\(category)] \(message)")
        }
    }

    // MARK: - User Identification

    func setUserID(_ userID: String?) {
        let message = userID != nil ? "User ID set: \(userID!)" : "User ID cleared"
        log(message, category: "User")
    }

    func setUserEmail(_ email: String?) {
        let message = email != nil ? "User Email set: \(email!)" : "User Email cleared"
        log(message, category: "User")
    }

    // MARK: - Authentication Flows

    func logLoginAttempt(email: String) {
        log("Login attempt for email: \(email)", category: "Auth")
    }

    func logLoginSuccess(userID: String, email: String, token: String?) {
        let tokenInfo = token != nil ? "Token: \(token!)" : "No token provided"
        log("Login successful. User ID: \(userID), Email: \(email). \(tokenInfo)", category: "Auth")
    }

    func logLoginFailure(email: String, error: Error?) {
        let errorMessage = error != nil ? " Error: \(error!.localizedDescription)" : ""
        log("Login failed for email: \(email).\(errorMessage)", category: "Auth")
    }

    func logLogout(userID: String?, email: String?) {
        let userIdentifier = [userID, email].compactMap { $0 }.joined(separator: ", ")
        log("Logout initiated for user: \(userIdentifier)", category: "Auth")
    }

    func logTokenRefresh(userID: String?, oldToken: String?, newToken: String?) {
        let userIDInfo = userID != nil ? "User ID: \(userID!)" : "Unknown User"
        let oldTokenSnippet = oldToken?.prefix(10) ?? "N/A"
        let newTokenSnippet = newToken?.prefix(10) ?? "N/A"
        log("Token refresh. \(userIDInfo). Old token (prefix): \(oldTokenSnippet). New token (prefix): \(newTokenSnippet)", category: "Auth")
    }

    // MARK: - API Calls

    func logAPIRequest(endpoint: String, method: String, userID: String?, payload: [String: Any]?, headers: [String: String]?) {
        let userIDInfo = userID != nil ? "User ID: \(userID!)" : "Unknown User"
        let payloadString = (payload != nil) ? " Payload: \(String(describing: payload!))" : ""
        let headersString = (headers != nil) ? " Headers: \(String(describing: headers!))" : ""
        log("API Request - \(method) \(endpoint). \(userIDInfo).\(payloadString).\(headersString)", category: "API")
    }

    func logAPIResponse(endpoint: String, method: String, statusCode: Int, userID: String?, responseData: Data?, error: Error?) {
        let userIDInfo = userID != nil ? "User ID: \(userID!)" : "Unknown User"
        let responseString = responseData != nil ? (String(data: responseData!, encoding: .utf8) ?? "Unreadable Data") : "No Data"
        let errorString = error != nil ? " Error: \(error!.localizedDescription)" : ""

        if statusCode >= 200 && statusCode < 300 {
            log("API Response Success - \(method) \(endpoint). Status: \(statusCode). \(userIDInfo). Response: \(responseString)", category: "API")
        } else {
            log("API Response Failure - \(method) \(endpoint). Status: \(statusCode). \(userIDInfo). Response: \(responseString).\(errorString)", category: "API_Error")
        }
    }

    // MARK: - User Data Changes

    func logUserDataChange(userID: String?, email: String?, dataType: String, oldValue: Any?, newValue: Any?) {
        let userIdentifier = [userID, email].compactMap { $0 }.joined(separator: ", ")
        log("User data change for \(userIdentifier). Type: \(dataType). Old: \(String(describing: oldValue ?? "nil")). New: \(String(describing: newValue ?? "nil"))", category: "User_Data")
    }

    // MARK: - Error Conditions

    func logError(_ error: Error, context: String, userID: String?, email: String?) {
        let userIdentifier = [userID, email].compactMap { $0 }.joined(separator: ", ")
        log("Error: \(error.localizedDescription). Context: \(context). User: \(userIdentifier). Details: \(error)", category: "Error")
    }

    func logCustomError(message: String, context: String, userID: String?, email: String?, metadata: [String: Any]?) {
        let userIdentifier = [userID, email].compactMap { $0 }.joined(separator: ", ")
        let metadataString = metadata != nil ? " Metadata: \(String(describing: metadata!))" : ""
        log("Custom Error: \(message). Context: \(context). User: \(userIdentifier).\(metadataString)", category: "Error")
    }

    // MARK: - Screen Views

    func logScreenView(screenName: String, userID: String?, email: String?) {
        let userIdentifier = [userID, email].compactMap { $0 }.joined(separator: ", ")
        log("Screen View: \(screenName). User: \(userIdentifier)", category: "Screen")
    }

    // MARK: - User Interactions (Taps, etc.)

    func logUserInteraction(element: String, action: String, screen: String, userID: String?) {
        let userIDInfo = userID != nil ? "User ID: \(userID!)" : "Unknown User"
        log("User Interaction: \(action) on \(element) (Screen: \(screen)). \(userIDInfo)", category: "Interaction")
    }
}